#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif

int Size;
float *a, *b, *finalVec;
float *m;

FILE *fp;

void InitProblemOnce(char *filename);
void InitPerRun();
void ForwardSub();
void BackSub();
void InitMat(float *ary, int nrow, int ncol);
void InitAry(float *ary, int ary_size);
void PrintMat(float *ary, int nrow, int ncolumn);
void PrintAry(float *ary, int ary_size);
void PrintDeviceProperties();
void checkCLError(cl_int err, const char *msg);

unsigned int totalKernelTime = 0;

cl_context context = NULL;
cl_command_queue commandQueue = NULL;
cl_program program = NULL;
cl_kernel kernelFan1 = NULL;
cl_kernel kernelFan2 = NULL;

const char* kernelSourceStr = 
"__kernel void Fan1(__global float *m_cuda, __global float *a_cuda, int Size, int t) {   \n"
"    int idx = get_global_id(0); \n"
"    if(idx >= Size-1-t) return; \n"
"    m_cuda[Size*(idx+t+1)+t] = a_cuda[Size*(idx+t+1)+t] / a_cuda[Size*t+t]; \n"
"} \n"
"\n"
"__kernel void Fan2(__global float *m_cuda, __global float *a_cuda, __global float *b_cuda, int Size, int j1, int t) { \n"
"    int xidx = get_global_id(0); \n"
"    int yidx = get_global_id(1); \n"
"    if(xidx >= Size-1-t) return; \n"
"    if(yidx >= Size-t) return; \n"
"    a_cuda[Size*(xidx+1+t)+(yidx+t)] -= m_cuda[Size*(xidx+1+t)+t] * a_cuda[Size*t+(yidx+t)]; \n"
"    if(yidx == 0){ \n"
"        b_cuda[xidx+1+t] -= m_cuda[Size*(xidx+1+t)+t] * b_cuda[t]; \n"
"    } \n"
"} \n";

void InitOpenCL() {
    cl_int err;
    cl_platform_id platform;
    cl_device_id device;

    err = clGetPlatformIDs(1, &platform, NULL);
    checkCLError(err, "Get Platform");

    err = clGetDeviceIDs(platform, CL_DEVICE_TYPE_ALL, 1, &device, NULL);
    checkCLError(err, "Get Device");

    cl_context_properties props[] = {CL_CONTEXT_PLATFORM, (cl_context_properties)platform, 0};
    context = clCreateContext(props, 1, &device, NULL, NULL, &err);
    checkCLError(err, "Create Context");

    commandQueue = clCreateCommandQueue(context, device, 0, &err);
    checkCLError(err, "Create Queue");

    program = clCreateProgramWithSource(context, 1, &kernelSourceStr, NULL, &err);
    checkCLError(err, "Create Program");

    err = clBuildProgram(program, 1, &device, NULL, NULL, NULL);
    checkCLError(err, "Build Program");

    kernelFan1 = clCreateKernel(program, "Fan1", &err);
    checkCLError(err, "Create Kernel Fan1");

    kernelFan2 = clCreateKernel(program, "Fan2", &err);
    checkCLError(err, "Create Kernel Fan2");
}

void
create_matrix(float *m, int size){
  int i,j;
  float lamda = -0.01;
  float coe[2*size-1];
  float coe_i =0.0;

  for (i=0; size > i; i++)
    {
      coe_i = 10*exp(lamda*i); 
      j=size-1+i;     
      coe[j]=coe_i;
      j=size-1-i;     
      coe[j]=coe_i;
    }


  for (i=0; size > i; i++) {
      for (j=0; size > j; j++) {
	m[i*size+j]=coe[size-1-i+j];
      }
  }


}


int main(int argc, char *argv[])
{
  printf("WG size of kernel 1 = %d, WG size of kernel 2= %d X %d\n", MAXBLOCKSIZE, BLOCK_SIZE_XY, BLOCK_SIZE_XY);
    int verbose = 0;
    int i, j;
    char flag;
    if (2 > argc) {
        printf("Usage: gaussian -f filename / -s size [-q]\n\n");
        printf("-q (quiet) suppresses printing the matrix and result values.\n");
        printf("-f (filename) path of input file\n");
        printf("-s (size) size of matrix. Create matrix and rhs in this program \n");
        printf("The first line of the file contains the dimension of the matrix, n.");
        printf("The second line of the file is a newline.\n");
        printf("The next n lines contain n tab separated values for the matrix.");
        printf("The next line of the file is a newline.\n");
        printf("The next line of the file is a 1xn vector with tab separated values.\n");
        printf("The next line of the file is a newline. (optional)\n");
        printf("The final line of the file is the pre-computed solution. (optional)\n");
        printf("Example: matrix4.txt:\n");
        printf("4\n");
        printf("\n");
        printf("-0.6	-0.5	0.7	0.3\n");
        printf("-0.3	-0.9	0.3	0.7\n");
        printf("-0.4	-0.5	-0.3	-0.8\n");	
        printf("0.0	-0.1	0.2	0.9\n");
        printf("\n");
        printf("-0.85	-0.68	0.24	-0.53\n");	
        printf("\n");
        printf("0.7	0.0	-0.4	-0.5\n");
        exit(0);
    }

    PrintDeviceProperties();

    InitOpenCL();

    for(i=1;argc > i;i++) {
      if ('-' == argv[i][0]) {
        flag = argv[i][1];
          switch (flag) {
            case 's': 
              i++;
              Size = atoi(argv[i]);
	      printf("Create matrix internally in parse, size = %d \n", Size);

