	      b = (float *) malloc(Size * sizeof(float));
	      for (j =0; Size > j; j++)
	    	b[j]=1.0;

	      m = (float *) malloc(Size * Size * sizeof(float));
              break;
            case 'f': 
              i++;
	      printf("Read file from %s \n", argv[i]);
	      InitProblemOnce(argv[i]);
              break;
            case 'q': 
	      verbose = 0;
              break;
	  }
      }
    }


    InitPerRun();

    struct timeval time_start;
    gettimeofday(&time_start, NULL);	


    ForwardSub();


    struct timeval time_end;
    gettimeofday(&time_end, NULL);
    unsigned int time_total = (time_end.tv_sec * 1000000 + time_end.tv_usec) - (time_start.tv_sec * 1000000 + time_start.tv_usec);

    if (verbose) {
        printf("Matrix m is: \n");
        PrintMat(m, Size, Size);

        printf("Matrix a is: \n");
        PrintMat(a, Size, Size);

        printf("Array b is: \n");
        PrintAry(b, Size);
    }
    BackSub();
    if (verbose) {
        printf("The final solution is: \n");
        PrintAry(finalVec,Size);
    }
    printf("\nTime total (including memory transfers)\t%f sec\n", time_total * 1e-6);
    printf("Time for CUDA kernels:\t%f sec\n",totalKernelTime * 1e-6);




    free(m);
    free(a);
    free(b);

#ifdef  TIMING
	printf("Exec: %f\n", kernel_time);
#endif

    if (kernelFan1) clReleaseKernel(kernelFan1);
    if (kernelFan2) clReleaseKernel(kernelFan2);
    if (program) clReleaseProgram(program);
    if (commandQueue) clReleaseCommandQueue(commandQueue);
    if (context) clReleaseContext(context);

    return 0;
}




void PrintDeviceProperties(){
    cl_platform_id platform;
    cl_device_id device;
    cl_uint numPlatforms;
    cl_uint numDevices;
    cl_int status;

    status = clGetPlatformIDs(1, &platform, &numPlatforms);
    if (status != CL_SUCCESS || numPlatforms == 0) {
        printf("No OpenCL platforms found\n");
        return;
    }

    status = clGetDeviceIDs(platform, CL_DEVICE_TYPE_ALL, 1, &device, &numDevices);
    if (status != CL_SUCCESS || numDevices == 0) {
        printf("No OpenCL devices found\n");
        return;
    }

    char name[256], vendor[256], version[256];
    size_t ret_size;
    cl_ulong mem_size;
    cl_uint max_threads, max_comp_units;
    cl_ulong shared_mem;

    clGetDeviceInfo(device, CL_DEVICE_NAME, sizeof(name), name, &ret_size);
    clGetDeviceInfo(device, CL_DEVICE_VENDOR, sizeof(vendor), vendor, &ret_size);
    clGetDeviceInfo(device, CL_DEVICE_VERSION, sizeof(version), version, &ret_size);
    clGetDeviceInfo(device, CL_DEVICE_GLOBAL_MEM_SIZE, sizeof(mem_size), &mem_size, &ret_size);
    clGetDeviceInfo(device, CL_DEVICE_LOCAL_MEM_SIZE, sizeof(shared_mem), &shared_mem, &ret_size);
    clGetDeviceInfo(device, CL_DEVICE_MAX_WORK_GROUP_SIZE, sizeof(max_threads), &max_threads, &ret_size);
    clGetDeviceInfo(device, CL_DEVICE_MAX_COMPUTE_UNITS, sizeof(max_comp_units), &max_comp_units, &ret_size);

    printf( "\nDevice Name \t\t - %s ", name );  
    printf( "\n**************************************");  
    printf( "\nTotal Global Memory\t\t\t - %lu KB", (unsigned long)(mem_size/1024) );  
    printf( "\nShared memory available per block \t - %lu KB", (unsigned long)(shared_mem/1024) );  
    printf( "\nMaximum threads per block \t\t - %d", max_threads );  
    printf( "\nNumber of Multi processors \t\t - %d\n\n", max_comp_units );  
    printf( "\nOpenCL ver \t\t\t\t - %s", version );  
}










void InitProblemOnce(char *filename)
{

	fp = fopen(filename, "r");

	fscanf(fp, "%d", &Size);	

	a = (float *) malloc(Size * Size * sizeof(float));

	InitMat(a, Size, Size);


	b = (float *) malloc(Size * sizeof(float));

	InitAry(b, Size);



	 m = (float *) malloc(Size * Size * sizeof(float));
}






void InitPerRun() 
{
	int i;
	for (i=0; Size*Size > i; i++)
			(m)[i] = 0.0;
}









void ForwardSub()
{
	int t;
    cl_mem m_cl, a_cl, b_cl;
    cl_int err;

    size_t mat_size = Size * Size * sizeof(float);
    size_t vec_size = Size * sizeof(float);

    m_cl = clCreateBuffer(context, CL_MEM_READ_WRITE, mat_size, NULL, &err);
    checkCLError(err, "Create m buffer");
    a_cl = clCreateBuffer(context, CL_MEM_READ_WRITE, mat_size, NULL, &err);
    checkCLError(err, "Create a buffer");
    b_cl = clCreateBuffer(context, CL_MEM_READ_WRITE, vec_size, NULL, &err);
    checkCLError(err, "Create b buffer");

    err = clEnqueueWriteBuffer(commandQueue, m_cl, CL_TRUE, 0, mat_size, m, 0, NULL, NULL);
    checkCLError(err, "Write m");
    err = clEnqueueWriteBuffer(commandQueue, a_cl, CL_TRUE, 0, mat_size, a, 0, NULL, NULL);
    checkCLError(err, "Write a");
    err = clEnqueueWriteBuffer(commandQueue, b_cl, CL_TRUE, 0, vec_size, b, 0, NULL, NULL);
    checkCLError(err, "Write b");

    int block_size, grid_size;

    block_size = MAXBLOCKSIZE;
    if (block_size > Size) block_size = Size;
    grid_size = (Size + block_size - 1) / block_size;

    size_t global1 = (size_t)grid_size * block_size;
    size_t local1 = (size_t)block_size;

    int blockSize2d, gridSize2d;
    blockSize2d = BLOCK_SIZE_XY;
    if (blockSize2d > Size) blockSize2d = Size;
    gridSize2d = (Size + blockSize2d - 1) / blockSize2d; 

    size_t global2[2] = {(size_t)gridSize2d * blockSize2d, (size_t)gridSize2d * blockSize2d};
    size_t local2[2] = {(size_t)blockSize2d, (size_t)blockSize2d};

#ifdef  TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    struct timeval time_start;
    gettimeofday(&time_start, NULL);

    for (t=0; t < Size-1; t++) {
        clSetKernelArg(kernelFan1, 0, sizeof(cl_mem), &m_cl);
        clSetKernelArg(kernelFan1, 1, sizeof(cl_mem), &a_cl);
        clSetKernelArg(kernelFan1, 2, sizeof(int), &Size);
        clSetKernelArg(kernelFan1, 3, sizeof(int), &t);

        err = clEnqueueNDRangeKernel(commandQueue, kernelFan1, 1, NULL, &global1, &local1, 0, NULL, NULL);
        checkCLError(err, "Fan1 enqueue");
        clFinish(commandQueue);

        clSetKernelArg(kernelFan2, 0, sizeof(cl_mem), &m_cl);
        clSetKernelArg(kernelFan2, 1, sizeof(cl_mem), &a_cl);
        clSetKernelArg(kernelFan2, 2, sizeof(cl_mem), &b_cl);
        clSetKernelArg(kernelFan2, 3, sizeof(int), &Size);
        int arg_j1 = Size - t;
        clSetKernelArg(kernelFan2, 4, sizeof(int), &arg_j1);
        clSetKernelArg(kernelFan2, 5, sizeof(int), &t);

        err = clEnqueueNDRangeKernel(commandQueue, kernelFan2, 2, NULL, global2, local2, 0, NULL, NULL);
        checkCLError(err, "Fan2 enqueue");
        clFinish(commandQueue);
    }

    struct timeval time_end;
    gettimeofday(&time_end, NULL);
    totalKernelTime = (time_end.tv_sec * 1000000 + time_end.tv_usec) - (time_start.tv_sec * 1000000 + time_start.tv_usec);

#ifdef  TIMING
    tvsub(&time_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    err = clEnqueueReadBuffer(commandQueue, m_cl, CL_TRUE, 0, mat_size, m, 0, NULL, NULL);
    checkCLError(err, "Read m");
    err = clEnqueueReadBuffer(commandQueue, a_cl, CL_TRUE, 0, mat_size, a, 0, NULL, NULL);
    checkCLError(err, "Read a");
    err = clEnqueueReadBuffer(commandQueue, b_cl, CL_TRUE, 0, vec_size, b, 0, NULL, NULL);
    checkCLError(err, "Read b");

    clReleaseMemObject(m_cl);
    clReleaseMemObject(a_cl);
    clReleaseMemObject(b_cl);
}






void BackSub()
{

	finalVec = (float *) malloc(Size * sizeof(float));

	int i,j;
	for(i=0;Size > i;i++){
		finalVec[Size-i-1]=b[Size-i-1];
		for(j=0;i > j;j++)
		{
			finalVec[Size-i-1]-=*(a+Size*(Size-i-1)+(Size-j-1)) * finalVec[Size-j-1];
		}
		finalVec[Size-i-1]=finalVec[Size-i-1]/ *(a+Size*(Size-i-1)+(Size-i-1));
	}
}

void InitMat(float *ary, int nrow, int ncol)
{
	int i, j;

	for (i=0; nrow > i; i++) {
		for (j=0; ncol > j; j++) {
			fscanf(fp, "%f",  ary+Size*i+j);
		}
	}  
}





void PrintMat(float *ary, int nrow, int ncol)
{
	int i, j;

	for (i=0; nrow > i; i++) {
		for (j=0; ncol > j; j++) {
			printf("%8.2f ", *(ary+Size*i+j));
		}
		printf("\n");
	}
	printf("\n");
}






void InitAry(float *ary, int ary_size)
{
	int i;

	for (i=0; ary_size > i; i++) {
		fscanf(fp, "%f",  &ary[i]);
	}
}  





void PrintAry(float *ary, int ary_size)
{
	int i;
	for (i=0; ary_size > i; i++) {
		printf("%.2f ", ary[i]);
	}
	printf("\n\n");
}

void checkCLError(cl_int err, const char *msg)
{
    if(err != CL_SUCCESS) 
    {
        fprintf(stderr, "OpenCL error: %s: %d.\n", msg, err);
        exit(EXIT_FAILURE);
    }                         
}
